<span class="line"><span style="color:#CBA6F7;">def</span><span style="color:#89B4FA;font-style:italic;"> detect_build_system</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;font-style:italic;">project_root</span><span style="color:#9399B2;">:</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#9399B2;">)</span><span style="color:#9399B2;"> -&gt;</span><span style="color:#FAB387;font-style:italic;"> str</span><span style="color:#94E2D5;"> |</span><span style="color:#CBA6F7;"> None</span><span style="color:#9399B2;">:</span></span>
